INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (72, 5, 'd39aaabe0b177a98b5e04fdbe7aa32caa41462d7c5c789e4b9d5ec09ada03ba1', 'Is there a character limit for the Ad Group Name?', 'We follow Google''s limits behind the scenes. Practically speaking:
Keep Ad Group Names short and scannable, ideally under 80 characters.
Use plain text without emojis or special characters, which can make reporting harder to read.
If you hit a limit, you will see a validation error and can shorten the name.', 'Is there a character limit for the Ad Group Name?

We follow Google''s limits behind the scenes. Practically speaking:
Keep Ad Group Names short and scannable, ideally under 80 characters.
Use plain text without emojis or special characters, which can make reporting harder to read.
If you hit a limit, you will see a validation error and can shorten the name.', 'Ad Group Name', '{}', 1, NULL, '2025-11-29 17:39:13.807746', '2025-11-29 17:39:13.807746');
INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (73, 5, '34847d330671079a7d1a7056f0e5676f8e7fd3382b3984fdd88093e35be9df6f', 'What are Headlines in my ad?', 'Headlines are short text snippets (up to 30 characters each) that appear as the bold, clickable part of your Google Search ad.
In a live ad, Google usually shows 2–3 headlines at a time, side by side. With Responsive Search Ads, Google can test different combinations of the headlines you provide.
On this page, you can:
Enter your own headlines
Edit AI-generated suggestions
Add extra headline options for Google to test', 'What are Headlines in my ad?

Headlines are short text snippets (up to 30 characters each) that appear as the bold, clickable part of your Google Search ad.
In a live ad, Google usually shows 2–3 headlines at a time, side by side. With Responsive Search Ads, Google can test different combinations of the headlines you provide.
On this page, you can:
Enter your own headlines
Edit AI-generated suggestions
Add extra headline options for Google to test', 'Headlines', '{}', 2, NULL, '2025-11-29 17:39:13.821228', '2025-11-29 17:39:13.821228');
