INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (77, 5, '2c59dfb5b62de051e005c81b5b5f3f574576aa6b98be3412f982d85ddbfb7d3c', 'What does "Refresh Suggestions" do for Headlines?', '"Refresh Suggestions" will:
Ask the AI to generate a new set of headline ideas, based on your latest business info and page content.
Leave any existing headlines you have edited and locked in place.
Add the new suggestions below headlines that are already locked
If you manually wrote or edited a headline and then locked it, that content will not be overwritten without your action.', 'What does "Refresh Suggestions" do for Headlines?

"Refresh Suggestions" will:
Ask the AI to generate a new set of headline ideas, based on your latest business info and page content.
Leave any existing headlines you have edited and locked in place.
Add the new suggestions below headlines that are already locked
