INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (88, 5, 'ecd4b84c0593ed6a389624d14951f2bf2ffccdfaafb993eb7cfacf1487959897', 'Can I bulk add headlines instead of typing them one by one?', 'Yes. On the Content page you can paste several headlines at once instead of typing them one by one.
A simple workflow:
Prepare your list
Create your headlines in a text editor or spreadsheet.
Put each headline on its own line and keep them under 30 characters.
Paste into the headline input
Click in the main "Enter headline" field.
Paste your list of headlines.
We will detect line breaks and split them into separate headline rows.
Review and select
Check that each new row looks correct and is within the character limit.
Use "Select 3–15" to choose which ones are active for your ad.
You can still edit or delete any individual headline after a bulk paste, and you can combine bulk-added headlines with AI-generated suggestions.', 'Can I bulk add headlines instead of typing them one by one?

Yes. On the Content page you can paste several headlines at once instead of typing them one by one.
A simple workflow:
Prepare your list
Create your headlines in a text editor or spreadsheet.
Put each headline on its own line and keep them under 30 characters.
Paste into the headline input
Click in the main "Enter headline" field.
Paste your list of headlines.
We will detect line breaks and split them into separate headline rows.
Review and select
Check that each new row looks correct and is within the character limit.
Use "Select 3–15" to choose which ones are active for your ad.
