INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (95, 5, 'bb095e0a3f308bc413d4dcc216306cedd70a2b617bd03d06844978e3a5acff23', 'What does the "lock" button on a Unique Feature do?', 'The lock button lets you protect a specific Unique Feature that you definitely want to use in your campaign.
When you click the lock icon on a line:
That Unique Feature is included in your campaign, as long as it passes Google''s policy checks.
It will not be replaced or removed if you click "Refresh Suggestions". New suggestions will appear around it, but the locked line stays exactly as you wrote it.
It is also treated as selected/active, so it counts toward your required number of Unique Features.
Use the lock when you have a line that is essential to your message and you do not want AI-generated suggestions to overwrite or swap it out.', 'What does the "lock" button on a Unique Feature do?

The lock button lets you protect a specific Unique Feature that you definitely want to use in your campaign.
When you click the lock icon on a line:
That Unique Feature is included in your campaign, as long as it passes Google''s policy checks.
It will not be replaced or removed if you click "Refresh Suggestions". New suggestions will appear around it, but the locked line stays exactly as you wrote it.
It is also treated as selected/active, so it counts toward your required number of Unique Features.
Use the lock when you have a line that is essential to your message and you do not want AI-generated suggestions to overwrite or swap it out.', 'Unique Features', '{}', 24, '[0.010471365,0.020838214,0.011320571,0.04324419,0.014619411,-0.09317752,-0.029186564,0.0054349196,-0.023869226,0.028977528,0.026103292,0.030545294,0.0019401095,-0.038540896,0.046823923,-0.054296937,-0.09579046,-0.0040533263,0.00020076786,0.02529328,-0.019727712,0.03373308,0.013822464,0.058843456,-0.016892672,-0.007832294,0.008106653,-0.004536721,0.022170814,0.028167516,0.0018355919,-0.0115230745,-0.017532842,-0.0075709997,-0.0030620415,-0.022419043,0.043113545,-0.0039814706,0.0042329663,0.013639558,-0.029421728,0.00081450306,-0.00676752,0.007616726,-0.009720145,0.02642991,0.024940532,-0.08523417,-0.035771176,0.02635152,-0.00325148,0.019270448,-0.04246031,-0.05016849,-0.0079694735,-0.007041879,0.012032598,0.002977121,-0.0087533565,0.003125732,-0.0034980762,-0.00518669,-0.019688519,0.03927252,0.010164345,0.0002465964,-0.088160664,0.044916473,-0.0140315,0.0048894677,0.018486565,-0.009413124,0.012176311,-0.010830645,0.013652623,-0.0027876827,-0.01896996,0.0443155,-0.043636132,-0.020576918,0.019152867,0.00060179323,-0.021582901,-0.05591696,-0.030728199,-0.0049711224,-0.013678752,0.022458237,-0.034412447,-0.0087076295,-0.032269835,0.02889914,-0.0028922004,0.00084430695,-0.014789253,0.03911574,0.008204638,0.03344566,0.015599265,0.058634423,0.04102319,-0.051788513,-0.03793992,-0.047660064,0.038958967,-0.026691204,0.008531256,0.006133882,0.024809886,-0.0038442912,-0.051239796,-0.017219288,-0.03924639,0.06453967,0.026717333,-0.05157948,0.0057256096,0.020694502,0.04651037,-0.006930829,-0.038227342,-0.018447371,-0.0044877282,-0.052206583,-0.010993954,-0.012502928,0.051213667,-0.0068263113,0.012816481,-0.004850274,-0.018943831,0.05513308,-0.0043538148,-0.017885588,-0.030101093,0.025423927,0.014345053,0.043688394,-0.032348223,-0.010020633,-0.02936947,-0.06197899,0.02324212,-0.012489864,-0.035457626,-0.0182383