INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (108, 5, 'fe4e8e18b80e6fcb3709f8622067caed1ac36e3966cc275b2b6942a30f6e5cdb', 'What makes a "good" keyword?', 'A good keyword matches how your ideal customer would search for your service, and it clearly relates to what''s on your landing page. For example, for pet portraits: "dog photo session," "cat portrait photographer," or "pet photography near me." A bad keyword is too broad ("photos," "camera") or not actually something you offer ("free pet portraits" if you don''t do them). Good keywords attract people who are ready to buy from you; bad keywords waste your budget on irrelevant searches.', 'What makes a "good" keyword?

A good keyword matches how your ideal customer would search for your service, and it clearly relates to what''s on your landing page. For example, for pet portraits: "dog photo session," "cat portrait photographer," or "pet photography near me." A bad keyword is too broad ("photos," "camera") or not actually something you offer ("free pet portraits" if you don''t do them). Good keywords attract people who are ready to buy from you; bad keywords waste your budget on irrelevant searches.', 'Keywords', '{}', 37, '[-0.0021790336,0.014871596,0.01006418,0.028044285,0.01838021,-0.061357643,1.913964e-05,0.048283443,0.041241594,0.010353487,0.041463193,-0.04328521,-0.03717899,-0.027108654,0.011467625,-0.015019327,-0.041635543,-0.008716134,0.0032900944,0.0110428985,0.027773444,0.009910294,-0.04739706,0.023932436,0.03267319,0.025951428,-0.0018804936,-0.012440189,0.07391479,0.008340651,0.0032223843,-0.023809327,-0.02491731,-0.016164243,-0.021950377,-0.012107793,5.3667933e-05,-0.061653107,0.007823592,-0.013615882,0.0044442434,0.037622184,0.08061193,0.01319731,-0.015019327,-0.009079306,0.026813192,-0.015918024,-0.0025822164,2.9887653e-05,-0.015893403,-0.009140861,0.031343613,0.026000671,-0.0010479674,-0.01612731,-0.013517395,-0.050671764,0.035110757,0.0628842,0.034150504,-0.019537436,0.042324957,-0.0038009977,-0.062194787,-0.034618318,-0.058156803,-0.00845145,-0.054463528,0.010839769,0.0597326,0.020731596,-0.00693105,0.0026160714,-0.035504706,0.021667225,0.037351344,0.027921176,-0.0029807824,-0.019438948,-0.048554283,0.043999244,-0.0009433245,0.00067094533,-0.069581345,-0.03959193,-0.010082646,-0.06628201,-0.027157899,-0.035283107,-0.0003210458,0.02064542,0.025101975,0.012938781,0.027822688,0.043605294,0.024067856,0.0032316176,-0.0066971425,0.04008437,-0.0025899105,-0.037129745,-0.012224748,-0.03306714,0.007780504,-0.05303546,0.0023621586,0.0030392592,0.03277168,-0.01717374,-0.10567697,0.011221407,-0.032353107,0.063918315,0.004908981,-0.036194116,-0.03264857,0.020399202,-0.0264931