INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (111, 5, '6b5419b5e9fa3c612bbc4573a62537c23e9eb47587011ce242c815230bfb813b', 'What does "Refresh Suggestions" do for keywords?', '"Refresh Suggestions" asks our AI to propose a new set of keyword ideas based on your latest business and landing page information. Any keywords you''ve manually added or edited will remain intact. We only replace or add to the unedited suggestion slots, so you don''t lose work you''ve already customized. "Refresh Suggestions" will: Ask the AI to generate a new set of keywords, Leave any existing keywords you have edited and locked in place, Add the new suggestions below keywords that are already locked', 'What does "Refresh Suggestions" do for keywords?

