INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (114, 5, '38f523a71ed5321e310de5d7bd6d1a7f7ab9df33a4d1ab9958a4b2e372d75743', 'Should my keywords be short or long phrases?', 'It''s useful to have a mix, but we recommend leaning toward specific, intent-rich phrases. Shorter keywords like "pet photographer" reach more people but can be too broad for smaller campaigns that are just getting started. Longer "long-tail" phrases like "pet portrait photographer in Brooklyn" often bring more qualified searchers who know what they want. A healthy set combines a few broader core terms with several more specific phrases tied to your location, service type, or niche.', 'Should my keywords be short or long phrases?

It''s useful to have a mix, but we recommend leaning toward specific, intent-rich phrases. Shorter keywords like "pet photographer" reach more people but can be too broad for smaller campaigns that are just getting started. Longer "long-tail" phrases like "pet portrait photographer in Brooklyn" often bring more qualified searchers who know what they want. A healthy set combines a few broader core terms with several more specific phrases tied to your location, service type, or niche.', 'Keywords', '{}', 43, '[0.015917342,0.014781292,0.05028921,-0.016523236,0.024223141,-0.024589201,-0.006626967,0.049809545,0.0006725582,0.07129354,-0.00020551487,-0.06755719,0.00240622,-0.03072388,-0.026406884,-0.0002924938,-0.028678987,-0.0045473613,0.01893419,0.0007498728,-0.0042002345,-0.01536194,-0.04698204,0.033702858,0.022178248,0.026533112,0.0016930322,0.0122062415,0.08331044,0.0068352427,-0.00822375,-0.024021177,-0.06104383,-0.024967887,-0.04246308,0.0161698,-0.0029742457,-0.026457375,0.01536194,-0.0044432236,-0.006402912,0.029436355,0.06563853,-0.008248996,-0.05281377,-0.0019091975,0.018113708,-0.003988803,0.028880952,0.029789792,-0.016409632,0.008248996,0.003777371,0.06715326,0.030572407,-0.017154377,-0.013859827,-0.06371986,0.020915968,0.0397618,0.010186595,-0.003086273,0.038802467,0.03993852,-0.04233685,-0.01757093,-0.044886652,0.026331147,-0.017709779,0.0028606406,0.026962288,0.011486743,-0.0014792336,-0.026129182,-0.031052072,0.01979254,0.004743015,0.0025371816,0.0215976,-0.03637889,-0.044356495,0.0145540815,0.0070056506,-0.012502877,-0.09563029,-0.017760271,-0.012641728,-0.038827714,-0.012679596,-0.01853026,-0.014263757,0.00044732026,0.01784863,-0.033551384,0.03998901,0.0074032685,0.02322594,0.0053236634,-0.016889298,0.037489697,0.012616483,-0.0015328805,-0.0018792184,-0.012376649,-0.0043359296,-0.05710552,0.00142322,0.042311605,0.034687437,-0.019641068,-0.061548743,0.0112974,0.015753247,0.054681942,-0.012988854,-0.024071667,-0.044205025,0.050036754,-0.021395635,0.0036195