INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (117, 5, 'f0160466dcc1a3b0a360710b4d742a807b0620d686dd6dd38e4aaa9bce486242', 'Will changing my keywords later affect my campaign?', 'Yes. When you add, remove, or edit keywords after launch, your ads become eligible for a different set of searches. That can improve results if you''re tightening up relevance or expanding into a new niche. In reporting, you may see a short adjustment period while performance stabilizes around your new keyword set. It''s normal to review your keywords regularly and tune them based on what''s working.', 'Will changing my keywords later affect my campaign?

