INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (118, 5, 'b8b2766f47228729d207beeac8617eb4ab8ca25bf97bd2b7e231bdf8897c7151', 'What is Location Targeting and why does it matter?', 'Location Targeting tells Google where potential customers should be when they see your ad. 

For a local service business, this might be your city plus a radius around it

For an online-only business, it might be specific regions or countries you serve. 

Getting this right helps you avoid paying for clicks from people who live too far away or who cannot realistically become customers.', 'What is Location Targeting and why does it matter?

Location Targeting tells Google where potential customers should be when they see your ad. 

For a local service business, this might be your city plus a radius around it

For an online-only business, it might be specific regions or countries you serve. 

