INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (119, 5, '71c57e682344f3ebc09e2606144ff77495c751b8d1327d5751421f649e9946af', 'How do I change my Location Targeting?', 'Start typing the name of a location (for example, "San Fran") in the search bar.

The system will suggest matching locations (like "San Francisco, CA, City, US" or "San Francisco County, CA, County, US").

Click on a suggestion to add it to your list of targeted locations and set a radius around that location if you would like. If you choose a specific address, it''s important to include a radius to capture the area around that address. 

You can toggle each location between "Targeted" and "Excluded" to fine-tune your campaign (for example, target all of California except San Francisco). 

You can remove any location from your list at any time. At least one targeted location is required to save your settings. Make sure not to duplicate locations between your targeted and excluded lists.', 'How do I change my Location Targeting?

Start typing the name of a location (for example, "San Fran") in the search bar.

The system will suggest matching locations (like "San Francisco, CA, City, US" or "San Francisco County, CA, County, US").

Click on a suggestion to add it to your list of targeted locations and set a radius around that location if you would like. If you choose a specific address, it''s important to include a radius to capture the area around that address. 

You can toggle each location between "Targeted" and "Excluded" to fine-tune your campaign (for example, target all of California except San Francisco). 

