INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (120, 5, 'd3798e3b23ee834d26f454850d583650b90043c80afb165d5799002e959d28dd', 'Should I start with a broad area (like the whole country) or a narrow local radius?', 'If you are a local service business (for example, pet photographer, plumber, HVAC, dentist), we strongly recommend starting with a narrow local focus: your city or a radius that roughly matches your real service area. This keeps your budget concentrated on people who can actually work with you. If you sell fully online and can serve customers anywhere, targeting a broader region or country can make sense, but you may still want to start with your strongest markets first.', 'Should I start with a broad area (like the whole country) or a narrow local radius?

If you are a local service business (for example, pet photographer, plumber, HVAC, dentist), we strongly recommend starting with a narrow local focus: your city or a radius that roughly matches your real service area. This keeps your budget concentrated on people who can actually work with you. If you sell fully online and can serve customers anywhere, targeting a broader region or country can make sense, but you may still want to start with your strongest markets first.', 'Location Targeting', '{}', 49, '[-0.012926533,0.011226212,0.09909659,0.03856791,-0.031302284,-0.02626278,-0.010638953,0.022698253,-0.036546648,0.057032436,-0.0140669085,0.0029772678,0.022370482,-0.04261044,0.023572315,0.021441791,-0.01896984,-0.028625475,0.0026955884,-0.016934918,0.053208422,-0.008310402,-0.062386055,-0.01940687,0.024733175,-0.015255084,-0.021660307,0.057087064,0.03326892,-0.015623828,-0.024869747,-0.022247566,-0.054273684,-0.03277726,-0.048291832,0.008569888,-0.0063266945,0.017836293,0.043320615,0.030045822,-0.007340741,0.007368055,0.032749947,-0.04853766,-0.013677678,-0.004264458,0.016839318,-0.005418491,0.029171763,-0.026440324,-0.0065076523,-0.057469465,0.008829375,-0.018696696,0.021141334,-0.009880979,0.0038444996,-0.03201246,0.0066373954,0.058343526,0.010413609,0.015091198,0.04826452,0.013186019,-0.0029055676,0.016689088,-0.017249035,-0.004749289,0.015446285,0.037966996,-0.010147294,-0.011724699,0.050012637,-0.015937943,0.022452423,-0.020513102,0.024036659,-0.0038888855,-0.026768098,-0.0074499985,-0.0041859294,0.008556231,0.026139867,0.021632992,-0.06872299,-0.020827219,0.03638276,-0.033787895,-0.0036874418,-0.020403845,0.06047405,0.015255084,0.019830244,-0.022971397,0.03482584,0.009170804,0.048564974,-0.0054901913,0.025320435,0.02290311,-0.023135284,0.02889862,0.020362874,0.0016328881,0.028243074,-0.0070266253,0.014326395,0.09587349,0.033651322,-0.033542063,-0.030701369,0.010577495,0.033186976,0.0077709425,-0.0391142,0.025948666,-0.032941148,-0.034661952,0.0057804068,-0.05