INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (122, 5, '11d7cb4b249a33ce3f716ffcade946d0467d15334a54d2282045d1754aa7c391', 'Can I add multiple locations or different radiuses?', 'Yes. You can add several locations by typing them into the location search bar one by one. For some types of locations (like a city or address), you can also set a radius around that point (for example, 10 miles). This is useful if you serve certain neighborhoods but not an entire metro area. 
Just be sure your combined locations still reflect areas you''re truly willing to serve so you don''t waste budget.', 'Can I add multiple locations or different radiuses?

Yes. You can add several locations by typing them into the location search bar one by one. For some types of locations (like a city or address), you can also set a radius around that point (for example, 10 miles). This is useful if you serve certain neighborhoods but not an entire metro area. 
