INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (125, 5, '89d800ab49a5f25a9b55b9da2ca702685ff14b48f51d50c16b7d68e1df3657bb', 'What is the Ad Schedule and what does it control?', 'The Ad Schedule determines which days of the week and hours of the day your ads are eligible to run. For example, you might choose the default of Monday–Friday from 9:00 AM to 5:00 PM to align with your business hours, or select "Always On" to let Google show your ads 24/7. This helps you align your ad spend with when customers are most likely to contact you or when you can respond quickly.', 'What is the Ad Schedule and what does it control?

The Ad Schedule determines which days of the week and hours of the day your ads are eligible to run. For example, you might choose the default of Monday–Friday from 9:00 AM to 5:00 PM to align with your business hours, or select "Always On" to let Google show your ads 24/7. This helps you align your ad spend with when customers are most likely to contact you or when you can respond quickly.', 'Ad Schedule', '{}', 54, '[0.0025267524,0.01807491,0.043144368,0.000614711,0.033908848,-0.014815314,0.0041197664,-0.042306833,-0.0072944765,0.003180369,0.013117608,-0.024922322,0.00050789706,-0.006915322,0.024605418,-0.024922322,-0.05305897,0.004416865,0.01247248,0.02194568,0.03205269,0.021866452,-0.030354982,0.033342946,-0.005608089,-0.006570122,0.01241589,0.011238813,0.05536785,-0.011634945,0.0059419707,-0.009665606,-0.015732076,0.008771481,-0.01709024,-0.04547588,-0.023858428,-0.028747821,-0.03273177,-0.014521045,-0.0621134,0.016784653,0.019206714,-0.021323187,-0.040541217,-0.0073397486,-0.030332346,-0.06319993,0.036014,0.023858428,0.004651714,0.02037247,-0.0010808728,-0.0478074,0.04352918,0.033705123,0.015698122,0.002124962,0.047083046,-0.035719734,-0.009897626,-0.025556134,0.012936519,0.0047252816,-0.043325454,-0.00028524996,-0.03671572,0.021051554,-0.044366714,0.022511581,0.032754406,0.015222764,0.05011628,-0.059895065,-0.030377619,-0.0056505315,0.008567756,0.042985916,0.039567865,0.009173271,0.0028238508,0.019116169,-0.06754606,0.025126047,-0.033750392,0.0073397486,-0.007424634,0.008862025,-0.038028613,0.008403645,0.00089907675,0.030785067,-0.023586795,0.0494372,0.016309295,0.017169466,0.017735368,-0.0080414675,0.05097645,0.037847526,0.03687417,-0.052606247,-0.027706562,-0.01131238,-0.025442952,-0.025012868,-0.01056539,0.021685364,0.01195185,-0.04866757,-0.03734953,0.017939093,-0.024786508,0.01321947,0.022375764,-0.022024905,0.02037247,0.046630323,0.021628775,-0.029426903,-0.039862137,0.029607993,0.02245499,-0.0073454077,-0.011561378,0.05767673,0.0011947606,-0.01841445,-