INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (127, 5, '485adf00a72a18574d89b89fb584fda4e56d199db757343049e83672b71ba6e4', 'Should I only run ads during my business hours?', 'It depends on how your customers typically contact you.

If most leads call you and you want someone available to answer, it often makes sense to run ads mainly during business hours.

If leads usually fill out a form, request callbacks, or book online, running ads longer hours or 24/7 can work well, as long as you respond promptly when you''re back online.

You can start with your business hours, then expand if you see demand outside those times.', 'Should I only run ads during my business hours?

It depends on how your customers typically contact you.

If most leads call you and you want someone available to answer, it often makes sense to run ads mainly during business hours.

If leads usually fill out a form, request callbacks, or book online, running ads longer hours or 24/7 can work well, as long as you respond promptly when you''re back online.

You can start with your business hours, then expand if you see demand outside those times.', 'Ad Scheduling', '{}', 56, '[-0.0056724017,0.037343822,0.07991431,0.022604125,0.002991902,-0.028697835,0.02542506,0.0045061707,0.03807653,0.02244537,0.020747924,-0.020918889,0.054806758,-0.016144058,0.0054648006,0.012529353,-0.0530971,-0.016473778,-0.02503428,0.011943184,0.0110883545,0.02999229,-0.009238261,-0.016144058,-0.023727614,0.041422576,0.010813588,0.04467093,0.052169,-0.021163126,0.021297457,-0.007638509,-0.05856801,0.016571473,-0.036708806,0.014776332,-0.00754692,-0.011772218,0.030114409,-0.034828182,-0.05197361,0.010911283,0.020528112,-0.055686012,-0.042912424,-0.0027003442,-0.025107553,0.008420067,0.05832377,0.049287006,-0.020784559,-0.022848362,-0.004777884,-0.026597397,0.017072158,0.01284686,-0.022604125,-0.027501075,0.0726849,0.026572974,-0.02867341,0.0045916536,0.024008486,-0.049506817,-0.034583945,0.038296346,-0.038223073,0.014825179,-0.059740342,0.019111536,-0.006759256,-0.008432278,0.041447,-0.039688494,-0.045037284,0.051192053,0.048578717,0.033655845,0.020442627,-0.006063181,0.003776513,0.0032269799,-0.030676154,0.07463879,-0.052266695,0.024704563,-0.019954154,0.019905306,-0.05182707,-0.019685494,0.022762878,0.038296346,0.025058705,-0.02708587,0.005354894,0.035121266,0.021102067,0.008542186,0.062475797,0.002524799,0.021163126,-0.010862436,0.0170111,0.010935707,-0.0034528992,0.0058250497,0.012724742,0.06482047,0.027183566,-0.013750537,-0.054513674,-0.009659569,-0.007485861,0.007626297,0.024521384,-0.013054462,-0.010202996,0.015130475,0.012871284,-0.052559778,0.0052358285,0.059544954,-0.032410234,0.021798143,0.0042100335,0.019600011,-0.0062768883,-0.021590542,-0.030871544,0.05509984,-0.024753409,-0.029894596,0.047284264,-0.009195519,-0.0660905,-0.05949611,-0.014715273,0.0125782,-0.054855607,0.017072158,0.058226075,0.017633904,-0.0493847,0.017377455,-0.080500476,0.029674781,-0.038711548,-0.01575328,-0.0013249852,0.021969108,-0.023410106,0.007992652,-0.014055