INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (128, 5, '8317fcb25590628be0f2546227acfa49d780a55c2fe287899674b7d445b2628f', 'What does the Time Zone setting affect?', 'The Time Zone setting tells Google which local time your Start Time and End Time refer to. For example, if you choose 9:00 AM to 5:00 PM and "Eastern Standard Time," your ads will run during that window in Eastern time. Make sure this matches where you operate or where your customers are, so you don''t accidentally show ads overnight or miss your peak hours.', 'What does the Time Zone setting affect?

The Time Zone setting tells Google which local time your Start Time and End Time refer to. For example, if you choose 9:00 AM to 5:00 PM and "Eastern Standard Time," your ads will run during that window in Eastern time. Make sure this matches where you operate or where your customers are, so you don''t accidentally show ads overnight or miss your peak hours.', 'Ad Scheduling', '{}', 57, '[-0.020784218,0.045706566,0.064213775,0.026055655,-0.0024615626,-0.028405445,0.023913808,-0.006186398,-0.00047860108,-0.009648702,0.011249887,0.022291828,-0.017061982,-0.027989553,0.036910444,-0.020149983,-0.10555347,-0.017872972,-0.010896379,0.0016687679,-0.0104700895,0.01880873,-0.03387443,-0.012986237,-0.0204723,0.0120088905,0.03418635,0.07785504,0.04198433,-0.021959115,-0.042545784,-0.00783957,-0.012882264,-0.027324125,0.008141092,-0.01649013,-0.0012814682,0.008614169,-0.010626049,-0.004426654,-0.03316741,0.032460395,-0.0032725527,-0.028363856,-0.014379477,0.007553644,-0.015055302,-0.010719624,0.013391732,0.018663168,0.013620473,-0.021439249,-0.006113617,-0.060345974,-0.00045293273,-0.0024173742,0.035745945,0.0027630846,0.058141746,0.019224623,-0.0027786805,0.0022523168,0.004101738,0.022271033,-0.007922749,0.015647948,-0.03225245,-0.019380582,-0.06230067,-0.001502411,-0.0043070847,0.016656488,0.008354237,-0.034768596,-0.014233914,0.0055521624,0.012279221,0.014972123,0.044708423,-0.00088377116,0.01587669,0.011177106,-0.006805038,0.05627023,-0.011489025,0.034893364,-0.0024160745,0.0044708424,-0.01761304,0.03988407,-0.009783867,-0.0041147345,0.03266834,0.046995834,0.008541388,-0.0038833944,-0.011208298,-0.016438143,0.0424834,0.019141443,0.03464383,-0.015096891,-0.040424734,0.017717013,-0.023227585,-0.022416595,-0.009045658,0.03337536,-0.0030308152,-0.01799774,-0.034498267,0.03530926,-0.023726657,0.061552063,-0.0013302056,-0.020524286,-0.012539153,0.01915184,0.080599934,-0.019609323,-0.03603707,-0.0032413607,-0.027823197,-0.013973982,-0.0024914548,0.018455222,-0.006597092,0.00686222