INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (129, 5, '1944427a3bfc79b50980bdf13961ab87f0cda943d8ab008dc7a430842368be77', 'What is the Daily Budget and how is it used?', 'The Daily Budget is the average amount you''re comfortable spending per day on this campaign. Google uses it to pace your ad spend across the month. On some days you might spend a little more or less than your daily setting, but over a month it aims to average out to roughly your daily budget multiplied by the number of days in the month.', 'What is the Daily Budget and how is it used?

