INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (130, 5, '9c92da59757039b83d6fca3074550773fdf5ccdfd22c43656dffcba3e928afa5', 'How much should I set as my Daily Budget?', 'A good starting point depends on your industry and goals, but you generally want a budget that can generate a meaningful number of clicks each week. 

We recommend that you aim to generate 10-15 clicks per day at a minimum, which can mean $50 or more, depending on the competitiveness of your industry and demand for your keywords

It''s often better to start with a realistic, sustainable amount than to go very low and receive almost no data or feedback from your Google ad.', 'How much should I set as my Daily Budget?

A good starting point depends on your industry and goals, but you generally want a budget that can generate a meaningful number of clicks each week. 

We recommend that you aim to generate 10-15 clicks per day at a minimum, which can mean $50 or more, depending on the competitiveness of your industry and demand for your keywords

