INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (131, 5, 'b7709b2d7638372b160333ab48e659f357989c75cd8b31e29057cc11410ae9e4', 'Is my Daily Budget a hard maximum or can Google spend more than that?', 'Google treats your Daily Budget as an average target. On a given day, Google might spend up to roughly twice your daily amount if there''s strong demand, and then spend less on quieter days so that, over the course of a month, you don''t exceed your daily budget multiplied by the number of days. If you want tighter control, choose a daily number that still feels comfortable even if a particular day spends a bit more.', 'Is my Daily Budget a hard maximum or can Google spend more than that?

Google treats your Daily Budget as an average target. On a given day, Google might spend up to roughly twice your daily amount if there''s strong demand, and then spend less on quieter days so that, over the course of a month, you don''t exceed your daily budget multiplied by the number of days. If you want tighter control, choose a daily number that still feels comfortable even if a particular day spends a bit more.', 'Daily Budget', '{}', 60, '[0.03141181,0.020557845,0.045452487,0.026476013,0.0057624266,-0.035509005,0.013178106,0.015586105,-0.025206123,-0.009566107,-0.004857929,0.0029231436,-0.037809186,-0.019299936,0.052760344,0.021827737,-0.058846235,-0.028800152,-0.05942128,0.0008243804,0.0038665761,0.039965604,-0.018509248,-0.008296217,0.026380172,-0.02484672,0.023205448,-0.0027614122,0.009614027,-0.047321383,-0.069915846,-0.0030129943,-0.04574001,-0.03610801,0.016987776,-0.002909666,0.0112732705,0.0060469536,0.040492725,0.020354183,-0.0051544365,0.012662962,0.037306022,0.011309211,-0.022762183,-0.028752232,0.020773487,-0.039055116,0.01734718,0.0021893627,-0.0123994,0.023265347,0.0015027534,0.028273027,0.04847147,-0.012039997,0.022510601,-0.0050496105,0.04744118,0.0013447659,0.003474228,-0.027841745,-0.0102789225,0.00015087434,0.010452635,0.014160474,-0.022546541,0.025278004,-0.012698903,0.009224675,-0.04811207,0.008326167,0.0083740875,-0.028656391,0.012543161,-0.042816866,0.03215458,-0.010081251,0.06363827,0.031339932,0.027889665,-0.00619371,-0.06617805,0.01860509,-0.021612095,-0.025733247,-0.02846471,0.0080985455,-0.06282362,0.008272257,-0.026164532,-0.02968668,0.028296988,0.025325924,0.014244335,0.010093232,-0.026667695,0.046698418,0.03452664,0.0139208725,-0.00869755,0.0014840345,0.028368868,-0.020821407,-0.015705906,-0.03491,0.0036149942,-0.01490324,0.037569582,-0.03946244,-0.012686922,0.01364533,-0.035389204,0.020677647,0.009272595,-0.008829331,-0.05956504,0.025805129,0.013453648,-0.028824111,-0.0472495,-0.023169506,-0.0005926404,-0.030836768,-0.011830346