INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (137, 5, '525713f7aa490587fc03b9c5a9952522998f6a1c3189af79270237cb066eefcc', 'How is the Campaign Name different from the Ad Group Name?', 'A Campaign is the higher level that controls budget, targeting, and dates. Inside each campaign are one or more Ad Groups, which hold your ads and keywords. Campaign Name describes the overall initiative, while Ad Group Name describes one specific cluster of ads and keywords within that campaign. Think of Campaign Name as the folder and Ad Group Name as the subfolder.

After the initial launch of your Campaign and first Ad Group, you will be able to add more Ad Groups to your Campaign if you would like to.', 'How is the Campaign Name different from the Ad Group Name?

A Campaign is the higher level that controls budget, targeting, and dates. Inside each campaign are one or more Ad Groups, which hold your ads and keywords. Campaign Name describes the overall initiative, while Ad Group Name describes one specific cluster of ads and keywords within that campaign. Think of Campaign Name as the folder and Ad Group Name as the subfolder.

After the initial launch of your Campaign and first Ad Group, you will be able to add more Ad Groups to your Campaign if you would like to.', 'Campaign Name', '{}', 66, '[0.001875199,-0.006567571,0.050814103,0.01844286,0.035019267,-0.027156848,0.017754605,-0.045051437,-0.020099334,0.0040507796,0.034062713,-0.0428117,-0.028626677,-0.019224435,0.027833436,-0.0020851747,-0.06826541,-0.01754463,0.0160748,-0.011344517,0.036115807,-0.019002795,-0.021720812,0.043931566,-0.008754817,-0.018057903,-0.009227263,0.02795009,0.031636328,0.0072908206,0.053427134,-0.0128785055,-0.042835027,0.022164093,-0.016016474,0.0018329122,0.018127896,-0.038635515,0.016343104,0.035742518,-0.025570365,0.055480227,0.010516279,0.011041218,-0.025547035,-0.014511649,0.0033129489,-0.050954085,-0.024893777,0.058046594,-0.023540601,0.015981479,0.010982892,-0.014756621,0.011869456,-0.016681397,0.02725017,0.0032779528,0.0046807067,-0.033992723,-0.006252608,0.0156198535,0.050487474,-0.0249871,0.029116621,-0.019364418,-0.037002373,0.008643997,-0.020041008,0.025243737,-0.026830219,0.011414508,-0.01060377,-0.03842554,-0.04211178,0.012178587,-0.01071459,0.0089822905,0.009886352,-0.017812932,-0.0005901919,-0.0065734037,0.00029272644,-0.009944679,-0.016273111,-0.020799253,0.005526442,0.01732299,-0.0038787164,-0.028789992,-0.021347523,0.04960091,-0.0034616815,0.0068300404,-0.0031321365,0.04512143,-0.020425962,0.0018956133,0.010055499,0.025827002,0.07470466,-0.004205345,0.0036599918,0.025057092,-0.023085654,-0.057579983,-0.02606031,0.03989537,0.039055467,0.0017702112,-0.05883984,-0.025150415,0.011128709,0.061452866,0.019049456,-0.004736117,-0.014558311,0.05221394,-0.036349114,0.007722437,-0.012831844,0.015946483,-0.023353957,-0.05291386,-0.004890682,0.028813323,0.049554247,-0.02369225,-0.048294395,0.0141966855,0.017089684,0.024263851,-0.03921878,-0.01545654,-0.032872852,-0.011437839,-0.04582135,0.052820537,-0.030119838,0.058233242,0.030119838,-0.058046594,0.017008025,-0.008463184,-0.03623246,0.0035141755,-0.01051