INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (139, 5, 'c2e0d545ec702808ce2fde6d04faf5a26895e1dc09ee4ab2ae8d94e34e9d74ae', 'What does Campaign Type mean and why is it fixed to Google Search?', 'Campaign Type tells Google which channel your ads will run on, such as Search, Display, or YouTube. We focus this experience on Google Search because it is the simplest and most effective starting point for most businesses.

To keep things straightforward and aligned with our templates, Campaign Type is fixed to Google Search for now and cannot be changed from this screen. If you would like to expand your campaign beyond Google Search, please contact the Launch10 team for help by emailing support@launch10.ai', 'What does Campaign Type mean and why is it fixed to Google Search?

Campaign Type tells Google which channel your ads will run on, such as Search, Display, or YouTube. We focus this experience on Google Search because it is the simplest and most effective starting point for most businesses.

