INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (140, 5, '73a16b646af7ad63b5db0ee22687799c568bfa0d33141bc93d2ec270bd57259f', 'What is the "Maximize Clicks" bidding strategy and why is it selected for me?', '"Maximize Clicks" tells Google to automatically set your bids in order to get as many clicks as possible within your daily budget. It is a smart bidding strategy that removes the need to set manual bids for each keyword. We set this as the default and only option for now because it is a strong, low-friction choice for early campaigns where the main goal is to drive traffic and learn what works.

If you would like to expand your campaign beyond this bidding strategy, please contact the Launch10 team for help by emailing support@launch10.ai', 'What is the "Maximize Clicks" bidding strategy and why is it selected for me?

"Maximize Clicks" tells Google to automatically set your bids in order to get as many clicks as possible within your daily budget. It is a smart bidding strategy that removes the need to set manual bids for each keyword. We set this as the default and only option for now because it is a strong, low-friction choice for early campaigns where the main goal is to drive traffic and learn what works.

If you would like to expand your campaign beyond this bidding strategy, please contact the Launch10 team for help by emailing support@launch10.ai', 'Bidding Strategy', '{}', 69, '[-0.0026485021,0.019595781,0.044883493,0.028233973,-0.015282955,-0.05526437,-0.036709182,0.018128918,-0.027456662,0.020247722,0.04503394,-0.013201765,-0.03533008,-0.009829234,0.058373615,-0.014116987,-0.04037007,-0.05145303,-0.0076540145,-0.027080543,-0.01017401,0.013327138,-0.0055132727,-0.016662057,-0.03578142,-0.058925256,-0.011571918,0.024021445,-0.0076602832,-0.005585362,-0.05165363,-0.015746834,-0.074421346,-0.022065628,-0.073669106,-0.06674852,0.019244738,-0.012574901,0.011691022,0.0162734,-0.01895638,0.04217544,0.04897065,0.03314859,-0.04618737,0.025726516,0.0061526746,-0.079285815,0.022140851,0.0474411,-0.038313955,0.012587437,0.006801479,0.016010117,0.04781722,0.020724138,0.035630975,0.0029509643,0.0038583507,0.052155122,-0.01942026,-0.009352817,0.009171027,0.042927675,0.051703777,0.03129307,-0.0711115,0.055013623,-0.0026438008,0.006419092,-0.0021626824,-0.03593187,-0.008036402,0.0010249234,0.026202934,0.017050713,-0.020247722,0.06063033,-0.0058141677,-0.017000563,-0.0038614848,-0.02029787,-0.004084022,-0.048118114,-0.04716528,-0.011954305,0.01160326,0.039141417,-0.026378455,-0.028058453,-0.049221396,-0.003416411,0.022905627,0.026428604,-0.016148027,0.031568892,0.0059771524,0.006118197,0.004717155,0.03232113,0.06765121,-0.053007655,-0.00089484896,-0.0046387967,-0.005823571,-0.027155766,-0.011139381,-0.011446545,0.062435698,0.0055414815,-0.03791276,0.004469543,-0.024723534,0.04345424,0.016210714,-0.036884703,-0.04355454,0.05105184,-0.016574295,-0.03227098,-0.027256066,-0.011935499,0.0059802867,-0.0042470065,-0.036884703,-0.009076997,0.008537893,-0.063238084,0.008030133,0.031117551,-0.014631016,0.0563175,0.031644117,-0.056518096,-0.014367733,-0.017878173,-0.036508586,0.016010117,-0.08650729,0.039191563,0.05145303,-0.036307987,-0.0011126844,0.04877005,-0.11704813,-0.019796379,-0.0347