INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (142, 5, 'd5a08bcd5cb4d8abb0324721bf864dbe457e4781689ae54bc55cd8628fcc61a9', 'How do the Start Date and End Date work for my campaign?', 'The Start Date is the first day your ads are eligible to run. The End Date is the last day they are scheduled to run. We default the End Date to 30 days after the Start Date so you have a clear test window, but you can change either date by clicking into the date fields. After the End Date passes, your campaign stops serving automatically unless you extend the date.', 'How do the Start Date and End Date work for my campaign?

The Start Date is the first day your ads are eligible to run. The End Date is the last day they are scheduled to run. We default the End Date to 30 days after the Start Date so you have a clear test window, but you can change either date by clicking into the date fields. After the End Date passes, your campaign stops serving automatically unless you extend the date.', 'Campaign Dates', '{}', 71, '[0.025009712,0.028592184,0.05123611,-0.0018081346,-0.005142763,-0.01708997,-0.0060214824,-0.017732112,-0.020041566,0.056733742,0.046865046,-0.013101934,0.0042922073,-0.047315672,0.039001632,-0.0152086085,-0.12941962,0.0025896882,-0.012437263,0.023950743,0.025910962,0.041187167,-0.012628778,0.025099838,-0.025212493,0.0020362637,0.016368968,0.041570198,0.047586046,0.027375495,0.03239997,0.0005076577,-0.05330899,-0.036771037,0.034788284,-0.028209154,-0.0017503982,-0.0037373747,-0.0040528127,0.014217232,-0.049658924,0.014296092,0.0070466553,-0.013090669,-0.014983296,-0.013755342,0.011817653,-0.060519,0.05326393,0.055201616,0.0053117475,-0.013800404,0.019872582,-0.0037261092,0.0050160247,-0.027330434,0.039587446,0.009063204,0.0033571597,-0.027690934,-0.004221797,0.035892315,0.02320721,-0.018036284,-0.004861122,-0.0074184216,-0.04316992,0.06619688,-0.027352965,0.014757983,0.00086604577,0.030867843,-0.0013054056,-0.021044208,-0.024108462,-0.012561184,0.05488618,0.008392899,0.008792829,-0.026519308,0.01727022,0.016661875,-0.016706938,0.055156555,-0.009998252,0.015580375,0.02026688,7.542696e-05,-0.011451519,-0.01381167,-0.036252815,0.013361044,0.023928212,0.064349316,0.0049456144,0.03294072,-0.06124,-0.06020356,0.019016394,-0.0010786847,0.051416364,0.0016307008,-0.041029446,-0.0069452645,-0.0049681454,-0.04499495,-0.012335871,0.049884237,0.023409992,-0.06385363,-0.05542693,-0.0055060796,-0.003835949,0.0025319518,0.007745125,-0.0139581235,-0.03967757,0.054525677,0.03595991,-0.04504001,-0.026541838,0.042606637,-0.023274804,-0.0117162615,-0.0044133128,0.017473001,0.018396784,-0.0117275