INSERT INTO public.document_chunks (id, document_id, question_hash, question, answer, content, section, context, "position", embedding, created_at, updated_at) VALUES (148, 5, '8102644deff8bf293498857945a957794027fc31a225180a06e1df616ee29054', 'How do I know I am ready to click "Next Step" and launch?', 'Before moving on, make sure:

Your Campaign Name clearly describes this campaign.
Your Start Date is when you want ads to begin, and your End Date (if set) matches how long you want to run this test.

Once those are correct, you can proceed to the next step to final review and launch. If anything looks off later, you will still be able to edit your campaign settings after it starts running.', 'How do I know I am ready to click "Next Step" and launch?

Before moving on, make sure:

Your Campaign Name clearly describes this campaign.
Your Start Date is when you want ads to begin, and your End Date (if set) matches how long you want to run this test.

